package com.example.cameramaltiagent.ui;

import android.content.Intent;
import android.os.Bundle;
import android.view.View;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;

import com.example.cameramaltiagent.BuildConfig;
import com.example.cameramaltiagent.MockAgentPipeline;
import com.example.cameramaltiagent.R;
import com.example.cameramaltiagent.agent.AgentPipeline;
import com.example.cameramaltiagent.model.AgentResult;
import com.google.gson.Gson;

import java.io.File;

/**
 * ProcessingActivity — AgentPipelineを実行してステップ進捗を表示する。
 *
 * MOCK_MODE = true のときはAPIを呼ばずダミーデータで動作確認できる。
 * APIキーを設定したら false に変更する。
 */
public class ProcessingActivity extends AppCompatActivity {

    // ★ APIキー未設定時は true にしてUIだけ確認する。キー設定後に false へ変更。
    private static final boolean MOCK_MODE = BuildConfig.GEMINI_API_KEY.isEmpty()
            || BuildConfig.GEMINI_API_KEY.equals("YOUR_GEMINI_API_KEY");

    public static final String EXTRA_CLOTHING_TEXT = "clothing_text";
    public static final String EXTRA_AGENT_RESULT = "agent_result";

    private AgentPipeline pipeline;
    private MockAgentPipeline mockPipeline;
    private TextView txtStep;
    private TextView txtStepDetail;
    private android.view.View progressBar;
    private android.view.View btnRetryBack;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_processing);

        txtStep = findViewById(R.id.txt_step);
        txtStepDetail = findViewById(R.id.txt_step_detail);
        progressBar = findViewById(R.id.progress_bar);
        btnRetryBack = findViewById(R.id.btn_retry_back);

        // 戻るボタン → InputActivityに戻る
        btnRetryBack.setOnClickListener(v -> finish());

        String selfiePath = getIntent().getStringExtra(CameraActivity.EXTRA_SELFIE_PATH);
        String clothingText = getIntent().getStringExtra(EXTRA_CLOTHING_TEXT);

        AgentPipeline.PipelineCallback callback = new AgentPipeline.PipelineCallback() {
            @Override
            public void onStepStarted(int step, String message) {
                String[] parts = message.split("\n", 2);
                txtStep.setText("Step " + step + "/4: " + parts[0]);
                txtStepDetail.setText(parts.length > 1 ? parts[1] : "");
                updateStepDot(step);
            }

            @Override
            public void onComplete(AgentResult result) {
                String resultJson = new Gson().toJson(result);
                Intent intent = new Intent(ProcessingActivity.this, ResultActivity.class);
                intent.putExtra(EXTRA_AGENT_RESULT, resultJson);
                // ★ selfiePath を ResultActivity にも渡す（AIチャット修正で使用）
                intent.putExtra(CameraActivity.EXTRA_SELFIE_PATH, selfiePath);
                startActivity(intent);
                finish();
            }

            @Override
            public void onError(String errorMessage) {
                txtStep.setText("❌ エラーが発生しました");
                txtStepDetail.setText(errorMessage);
                progressBar.setVisibility(View.GONE);
                btnRetryBack.setVisibility(View.VISIBLE);
            }
        };

        if (MOCK_MODE) {
            // APIキー未設定 → モックで動作確認
            txtStepDetail.setText(" モックモードで動作中（APIキー未設定）");
            mockPipeline = new MockAgentPipeline();
            mockPipeline.execute(new File(selfiePath != null ? selfiePath : ""), clothingText, callback);
        } else {
            // 本番: 実際のAPIを呼ぶ
            pipeline = new AgentPipeline();
            pipeline.execute(new File(selfiePath), clothingText, callback);
        }
    }

    private void updateStepDot(int activeStep) {
        int[] dotIds    = {R.id.step1_dot,   R.id.step2_dot,   R.id.step3_dot,   R.id.step4_dot};
        int[] labelIds  = {R.id.step1_label, R.id.step2_label, R.id.step3_label, R.id.step4_label};

        int colorDone     = getResources().getColor(R.color.step_done,   getTheme());
        int colorActive   = getResources().getColor(R.color.step_active, getTheme());
        int colorInactive = getResources().getColor(R.color.step_inactive, getTheme());

        for (int i = 0; i < dotIds.length; i++) {
            View dot     = findViewById(dotIds[i]);
            android.widget.TextView label = findViewById(labelIds[i]);
            if (dot == null || label == null) continue;

            if (i < activeStep - 1) {
                // 完了済み: 緑ドット + 通常テキスト
                dot.setBackgroundResource(R.drawable.step_dot_inactive);
                dot.getBackground().setTint(colorDone);
                label.setTextColor(colorDone);
            } else if (i == activeStep - 1) {
                // 実行中: 黒ドット + 太字テキスト
                dot.setBackgroundResource(R.drawable.step_dot_inactive);
                dot.getBackground().setTint(colorActive);
                label.setTextColor(colorActive);
                label.setTypeface(null, android.graphics.Typeface.BOLD);
            } else {
                // 未実行: グレー
                dot.setBackgroundResource(R.drawable.step_dot_inactive);
                dot.getBackground().setTint(colorInactive);
                label.setTextColor(colorInactive);
                label.setTypeface(null, android.graphics.Typeface.NORMAL);
            }
        }
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (pipeline != null) pipeline.shutdown();
        if (mockPipeline != null) mockPipeline.shutdown();
    }
}

package com.example.cameramaltiagent.ui;

import android.content.Intent;
import android.os.Bundle;
import android.view.View;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;

import com.example.cameramaltiagent.BuildConfig;
import com.example.cameramaltiagent.MockAgentPipeline;
import com.example.cameramaltiagent.R;
import com.example.cameramaltiagent.agent.AgentPipeline;
import com.example.cameramaltiagent.model.AgentResult;
import com.google.gson.Gson;

import java.io.File;

/**
 * ProcessingActivity — AgentPipelineを実行してステップ進捗を表示する。
 *
 * MOCK_MODE = true のときはAPIを呼ばずダミーデータで動作確認できる。
 * APIキーを設定したら false に変更する。
 */
public class ProcessingActivity extends AppCompatActivity {

    // ★ APIキー未設定時は true にしてUIだけ確認する。キー設定後に false へ変更。
    private static final boolean MOCK_MODE = BuildConfig.GEMINI_API_KEY.isEmpty()
            || BuildConfig.GEMINI_API_KEY.equals("YOUR_GEMINI_API_KEY");

    public static final String EXTRA_CLOTHING_TEXT = "clothing_text";
    public static final String EXTRA_AGENT_RESULT = "agent_result";

    private AgentPipeline pipeline;
    private MockAgentPipeline mockPipeline;
    private TextView txtStep;
    private TextView txtStepDetail;
    private android.view.View progressBar;
    private android.view.View btnRetryBack;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_processing);

        txtStep = findViewById(R.id.txt_step);
        txtStepDetail = findViewById(R.id.txt_step_detail);
        progressBar = findViewById(R.id.progress_bar);
        btnRetryBack = findViewById(R.id.btn_retry_back);

        // 戻るボタン → InputActivityに戻る
        btnRetryBack.setOnClickListener(v -> finish());

        String selfiePath = getIntent().getStringExtra(CameraActivity.EXTRA_SELFIE_PATH);
        String clothingText = getIntent().getStringExtra(EXTRA_CLOTHING_TEXT);

        AgentPipeline.PipelineCallback callback = new AgentPipeline.PipelineCallback() {
            @Override
            public void onStepStarted(int step, String message) {
                String[] parts = message.split("\n", 2);
                txtStep.setText("Step " + step + "/4: " + parts[0]);
                txtStepDetail.setText(parts.length > 1 ? parts[1] : "");
                updateStepDot(step);
            }

            @Override
            public void onComplete(AgentResult result) {
                String resultJson = new Gson().toJson(result);
                Intent intent = new Intent(ProcessingActivity.this, ResultActivity.class);
                intent.putExtra(EXTRA_AGENT_RESULT, resultJson);
                // ★ selfiePath を ResultActivity にも渡す（AIチャット修正で使用）
                intent.putExtra(CameraActivity.EXTRA_SELFIE_PATH, selfiePath);
                startActivity(intent);
                finish();
            }

            @Override
            public void onError(String errorMessage) {
                txtStep.setText("❌ エラーが発生しました");
                txtStepDetail.setText(errorMessage);
                progressBar.setVisibility(View.GONE);
                btnRetryBack.setVisibility(View.VISIBLE);
            }
        };

        if (MOCK_MODE) {
            // APIキー未設定 → モックで動作確認
            txtStepDetail.setText(" モックモードで動作中（APIキー未設定）");
            mockPipeline = new MockAgentPipeline();
            mockPipeline.execute(new File(selfiePath != null ? selfiePath : ""), clothingText, callback);
        } else {
            // 本番: selfiePath が取れていない場合はエラー表示して終了
            if (selfiePath == null) {
                txtStepDetail.setText("写真が取得できませんでした。\n戻って撮り直してください。");
                progressBar.setVisibility(android.view.View.GONE);
                btnRetryBack.setVisibility(android.view.View.VISIBLE);
                return;
            }
            pipeline = new AgentPipeline();
            pipeline.execute(new File(selfiePath), clothingText, callback);
        }
    }

    private void updateStepDot(int activeStep) {
        int[] dotIds    = {R.id.step1_dot,   R.id.step2_dot,   R.id.step3_dot,   R.id.step4_dot};
        int[] labelIds  = {R.id.step1_label, R.id.step2_label, R.id.step3_label, R.id.step4_label};

        int colorDone     = getResources().getColor(R.color.step_done,   getTheme());
        int colorActive   = getResources().getColor(R.color.step_active, getTheme());
        int colorInactive = getResources().getColor(R.color.step_inactive, getTheme());

        for (int i = 0; i < dotIds.length; i++) {
            View dot     = findViewById(dotIds[i]);
            android.widget.TextView label = findViewById(labelIds[i]);
            if (dot == null || label == null) continue;

            if (i < activeStep - 1) {
                // 完了済み: 緑ドット + 通常テキスト（BOLD解除を忘れずに）
                dot.setBackgroundResource(R.drawable.step_dot_inactive);
                dot.getBackground().setTint(colorDone);
                label.setTextColor(colorDone);
                label.setTypeface(null, android.graphics.Typeface.NORMAL);
            } else if (i == activeStep - 1) {
                // 実行中: 黒ドット + 太字テキスト
                dot.setBackgroundResource(R.drawable.step_dot_inactive);
                dot.getBackground().setTint(colorActive);
                label.setTextColor(colorActive);
                label.setTypeface(null, android.graphics.Typeface.BOLD);
            } else {
                // 未実行: グレー
                dot.setBackgroundResource(R.drawable.step_dot_inactive);
                dot.getBackground().setTint(colorInactive);
                label.setTextColor(colorInactive);
                label.setTypeface(null, android.graphics.Typeface.NORMAL);
            }
        }
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (pipeline != null) pipeline.shutdown();
        if (mockPipeline != null) mockPipeline.shutdown();
    }
}

package com.example.cameramaltiagent.ui;

import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.os.Environment;
import android.view.View;
import android.widget.EditText;
import android.widget.ImageView;
import android.widget.LinearLayout;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.bumptech.glide.Glide;
import com.example.cameramaltiagent.R;
import com.example.cameramaltiagent.api.GeminiApiClient;
import com.example.cameramaltiagent.model.AgentResult;
import com.example.cameramaltiagent.model.Product;
import com.google.gson.Gson;

import java.io.File;
import java.util.concurrent.Executors;

/**
 * ResultActivity — 試着結果・商品リンク・AI修正チャットを表示。
 */
public class ResultActivity extends AppCompatActivity {

    private AgentResult result;
    private ImageView imgResult;
    private File tryOnImageFile;  // 現在表示中の試着画像ファイル

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_result);

        String resultJson = getIntent().getStringExtra(ProcessingActivity.EXTRA_AGENT_RESULT);
        result = new Gson().fromJson(resultJson, AgentResult.class);

        if (result == null || !result.success) {
            Toast.makeText(this, "結果の取得に失敗しました", Toast.LENGTH_SHORT).show();
            finish();
            return;
        }

        imgResult = findViewById(R.id.img_tryon_result);

        // ── 試着画像を表示 ─────────────────────────────────────────
        if (result.tryOnResult != null && result.tryOnResult.outputImageUrl != null) {
            if (result.tryOnResult.isLocalFile) {
                // Gemini生成のローカルファイル
                // ※ キャッシュをスキップしないと前回の古い画像が表示されるので必ず無効化
                tryOnImageFile = new File(result.tryOnResult.outputImageUrl);
                Glide.with(this)
                        .load(tryOnImageFile)
                        .skipMemoryCache(true)
                        .diskCacheStrategy(com.bumptech.glide.load.engine.DiskCacheStrategy.NONE)
                        .placeholder(R.drawable.ic_launcher_background)
                        .into(imgResult);
            } else {
                // 楽天URL（フォールバック）
                Glide.with(this).load(result.tryOnResult.outputImageUrl)
                        .placeholder(R.drawable.ic_launcher_background)
                        .into(imgResult);
            }
        }

        // ── AI試着レポート（テキストフォールバック時） ─────────────
        TextView txtTryOnDesc = findViewById(R.id.txt_tryon_description);
        if (txtTryOnDesc != null && result.tryOnResult != null
                && result.tryOnResult.tryOnDescription != null) {
            txtTryOnDesc.setText(" AI試着レポート\n" + result.tryOnResult.tryOnDescription);
            txtTryOnDesc.setVisibility(View.VISIBLE);
        }

        // ── TOP商品カード ──────────────────────────────────────────
        if (result.selectedProduct != null) {
            setupProductCard(
                    findViewById(R.id.card_top_product),
                    result.selectedProduct,
                    result.bottomProduct != null ? "TOP" : null);
        }

        // ── BOTTOM商品カード（複合コーデ時のみ表示） ──────────────
        LinearLayout cardBottom = findViewById(R.id.card_bottom_product);
        if (result.bottomProduct != null) {
            cardBottom.setVisibility(View.VISIBLE);
            setupProductCard(cardBottom, result.bottomProduct, "BOTTOM");
        } else {
            cardBottom.setVisibility(View.GONE);
        }

        // ── スタイリングコメント ───────────────────────────────────
        TextView txtComment = findViewById(R.id.txt_styling_comment);
        txtComment.setText(result.stylingComment);

        // ── AI修正チャット ─────────────────────────────────────────
        setupRefinementChat();

        // ── やり直しボタン ─────────────────────────────────────────
        findViewById(R.id.btn_retry).setOnClickListener(v -> {
            Intent intent = new Intent(this, CameraActivity.class);
            intent.setFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP);
            startActivity(intent);
            finish();
        });
    }

    /** 商品カードをセットアップ */
    private void setupProductCard(LinearLayout card, Product product, String label) {
        if (card == null || product == null) return;
        card.setVisibility(View.VISIBLE);

        ImageView img = card.findViewById(R.id.img_product);
        TextView txtName  = card.findViewById(R.id.txt_product_name);
        TextView txtPrice = card.findViewById(R.id.txt_product_price);
        TextView txtLabel = card.findViewById(R.id.txt_product_label);

        if (img != null) {
            Glide.with(this).load(product.imageUrl)
                    .placeholder(R.drawable.ic_launcher_background).into(img);
        }
        if (txtName  != null) txtName.setText(product.name);
        if (txtPrice != null) txtPrice.setText(product.price);
        if (txtLabel != null && label != null) {
            txtLabel.setText(label);
            txtLabel.setVisibility(View.VISIBLE);
        }

        card.setOnClickListener(v -> {
            Intent i = new Intent(Intent.ACTION_VIEW, Uri.parse(product.purchaseUrl));
            startActivity(i);
        });
    }

    /** AI修正チャット：ユーザーのリクエストで試着画像を更新 */
    private void setupRefinementChat() {
        EditText etRefine = findViewById(R.id.et_refinement);
        View btnRefine    = findViewById(R.id.btn_send_refinement);
        TextView txtStatus = findViewById(R.id.txt_refinement_status);

        if (btnRefine == null || etRefine == null) return;

        btnRefine.setOnClickListener(v -> {
            String request = etRefine.getText().toString().trim();
            if (request.isEmpty()) return;

            btnRefine.setEnabled(false);
            etRefine.setEnabled(false);
            if (txtStatus != null) {
                txtStatus.setText(" AIが修正中...");
                txtStatus.setVisibility(View.VISIBLE);
            }

            // 現在のコーデ説明 + ユーザー修正リクエストで新画像を生成
            String currentCoord = (result.styleAnalysis != null
                    && result.styleAnalysis.garmentDescForTryOn != null)
                    ? result.styleAnalysis.garmentDescForTryOn
                    : "fashion outfit";

            Executors.newSingleThreadExecutor().execute(() -> {
                try {
                    String imagePrompt = "Professional fashion magazine photo of a fashion model. "
                            + "Base outfit: " + currentCoord + ". "
                            + "Modification request: " + request + ". "
                            + "Clean white studio background. Full body shot. "
                            + "High-end fashion photography. Natural lighting.";

                    GeminiApiClient client = new GeminiApiClient();
                    byte[] newImageBytes = client.generateImageFromText(imagePrompt);

                    runOnUiThread(() -> {
                        btnRefine.setEnabled(true);
                        etRefine.setEnabled(true);
                        etRefine.setText("");

                        if (newImageBytes != null && newImageBytes.length > 0) {
                            // 新画像をキャッシュディレクトリに保存して表示（キャッシュ無効化で最新画像を確実に表示）
                            File dir = getCacheDir();
                            File outFile = new File(dir, "tryon_refined_" + System.currentTimeMillis() + ".png");
                            try (java.io.FileOutputStream fos = new java.io.FileOutputStream(outFile)) {
                                fos.write(newImageBytes);
                                tryOnImageFile = outFile;
                                Glide.with(ResultActivity.this)
                                        .load(outFile)
                                        .skipMemoryCache(true)
                                        .diskCacheStrategy(com.bumptech.glide.load.engine.DiskCacheStrategy.NONE)
                                        .into(imgResult);
                                if (txtStatus != null) txtStatus.setText("✅ 修正完了！");
                            } catch (Exception e) {
                                if (txtStatus != null) txtStatus.setText("❌ 保存エラー: " + e.getMessage());
                            }
                        } else {
                            if (txtStatus != null) txtStatus.setText("❌ 画像を生成できませんでした。再度お試しください。");
                        }
                    });
                } catch (Exception e) {
                    runOnUiThread(() -> {
                        btnRefine.setEnabled(true);
                        etRefine.setEnabled(true);
                        if (txtStatus != null) txtStatus.setText("❌ エラー: " + e.getMessage());
                    });
                }
            });
        });
    }
}

package com.example.cameramaltiagent.ui;

import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.view.View;
import android.widget.EditText;
import android.widget.ImageView;
import android.widget.LinearLayout;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.bumptech.glide.Glide;
import com.example.cameramaltiagent.R;
import com.example.cameramaltiagent.api.GeminiApiClient;
import com.example.cameramaltiagent.model.AgentResult;
import com.example.cameramaltiagent.model.Product;
import com.google.gson.Gson;

import java.io.File;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

/**
 * ResultActivity — 試着結果・商品リンク・AI修正チャットを表示。
 */
public class ResultActivity extends AppCompatActivity {

    private AgentResult result;
    private ImageView imgResult;
    private File tryOnImageFile;
    // AIチャット用Executor（Activity破棄時にshutdown）
    private final ExecutorService chatExecutor = Executors.newSingleThreadExecutor();

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_result);

        String resultJson = getIntent().getStringExtra(ProcessingActivity.EXTRA_AGENT_RESULT);
        result = new Gson().fromJson(resultJson, AgentResult.class);

        if (result == null || !result.success) {
            Toast.makeText(this, "結果の取得に失敗しました", Toast.LENGTH_SHORT).show();
            finish();
            return;
        }

        imgResult = findViewById(R.id.img_tryon_result);

        // ── 試着画像を表示 ─────────────────────────────────────────
        if (result.tryOnResult != null && result.tryOnResult.outputImageUrl != null) {
            if (result.tryOnResult.isLocalFile) {
                // Gemini生成のローカルファイル
                // ※ キャッシュをスキップしないと前回の古い画像が表示されるので必ず無効化
                tryOnImageFile = new File(result.tryOnResult.outputImageUrl);
                Glide.with(this)
                        .load(tryOnImageFile)
                        .skipMemoryCache(true)
                        .diskCacheStrategy(com.bumptech.glide.load.engine.DiskCacheStrategy.NONE)
                        .placeholder(R.drawable.ic_launcher_background)
                        .into(imgResult);
            } else {
                // 楽天URL（フォールバック）
                Glide.with(this).load(result.tryOnResult.outputImageUrl)
                        .placeholder(R.drawable.ic_launcher_background)
                        .into(imgResult);
            }
        }

        // ── AI試着レポート（テキストフォールバック時） ─────────────
        TextView txtTryOnDesc = findViewById(R.id.txt_tryon_description);
        if (txtTryOnDesc != null && result.tryOnResult != null
                && result.tryOnResult.tryOnDescription != null) {
            txtTryOnDesc.setText(" AI試着レポート\n" + result.tryOnResult.tryOnDescription);
            txtTryOnDesc.setVisibility(View.VISIBLE);
        }

        // ── TOP商品カード ──────────────────────────────────────────
        if (result.selectedProduct != null) {
            setupProductCard(
                    findViewById(R.id.card_top_product),
                    result.selectedProduct,
                    result.bottomProduct != null ? "TOP" : null);
        }

        // ── BOTTOM商品カード（複合コーデ時のみ表示） ──────────────
        LinearLayout cardBottom = findViewById(R.id.card_bottom_product);
        if (result.bottomProduct != null) {
            cardBottom.setVisibility(View.VISIBLE);
            setupProductCard(cardBottom, result.bottomProduct, "BOTTOM");
        } else {
            cardBottom.setVisibility(View.GONE);
        }

        // ── スタイリングコメント ───────────────────────────────────
        TextView txtComment = findViewById(R.id.txt_styling_comment);
        txtComment.setText(result.stylingComment);

        // ── AI修正チャット ─────────────────────────────────────────
        setupRefinementChat();

        // ── やり直しボタン ─────────────────────────────────────────
        findViewById(R.id.btn_retry).setOnClickListener(v -> {
            Intent intent = new Intent(this, CameraActivity.class);
            intent.setFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP);
            startActivity(intent);
            finish();
        });
    }

    /** 商品カードをセットアップ */
    private void setupProductCard(LinearLayout card, Product product, String label) {
        if (card == null || product == null) return;
        card.setVisibility(View.VISIBLE);

        ImageView img = card.findViewById(R.id.img_product);
        TextView txtName  = card.findViewById(R.id.txt_product_name);
        TextView txtPrice = card.findViewById(R.id.txt_product_price);
        TextView txtLabel = card.findViewById(R.id.txt_product_label);

        if (img != null) {
            Glide.with(this).load(product.imageUrl)
                    .placeholder(R.drawable.ic_launcher_background).into(img);
        }
        if (txtName  != null) txtName.setText(product.name);
        if (txtPrice != null) txtPrice.setText(product.price);
        if (txtLabel != null && label != null) {
            txtLabel.setText(label);
            txtLabel.setVisibility(View.VISIBLE);
        }

        card.setOnClickListener(v -> {
            Intent i = new Intent(Intent.ACTION_VIEW, Uri.parse(product.purchaseUrl));
            startActivity(i);
        });
    }

    /** AI修正チャット：ユーザーのリクエストで試着画像を更新 */
    private void setupRefinementChat() {
        EditText etRefine = findViewById(R.id.et_refinement);
        View btnRefine    = findViewById(R.id.btn_send_refinement);
        TextView txtStatus = findViewById(R.id.txt_refinement_status);

        if (btnRefine == null || etRefine == null) return;

        btnRefine.setOnClickListener(v -> {
            String request = etRefine.getText().toString().trim();
            if (request.isEmpty()) return;

            btnRefine.setEnabled(false);
            etRefine.setEnabled(false);
            if (txtStatus != null) {
                txtStatus.setText(" AIが修正中...");
                txtStatus.setVisibility(View.VISIBLE);
            }

            String currentCoord = (result.styleAnalysis != null
                    && result.styleAnalysis.garmentDescForTryOn != null)
                    ? result.styleAnalysis.garmentDescForTryOn
                    : "fashion outfit";

            // 共有Executorを使用してリソースリークを防止
            chatExecutor.execute(() -> {
                try {
                    String imagePrompt = "Professional fashion magazine photo of a fashion model. "
                            + "Base outfit: " + currentCoord + ". "
                            + "Modification request: " + request + ". "
                            + "Clean white studio background. Full body shot. "
                            + "High-end fashion photography. Natural lighting.";

                    GeminiApiClient client = new GeminiApiClient();
                    byte[] newImageBytes = client.generateImageFromText(imagePrompt);

                    runOnUiThread(() -> {
                        btnRefine.setEnabled(true);
                        etRefine.setEnabled(true);
                        etRefine.setText("");

                        if (newImageBytes != null && newImageBytes.length > 0) {
                            File dir = getCacheDir();
                            File outFile = new File(dir, "tryon_refined_" + System.currentTimeMillis() + ".png");
                            try (java.io.FileOutputStream fos = new java.io.FileOutputStream(outFile)) {
                                fos.write(newImageBytes);
                                tryOnImageFile = outFile;
                                Glide.with(ResultActivity.this)
                                        .load(outFile)
                                        .skipMemoryCache(true)
                                        .diskCacheStrategy(com.bumptech.glide.load.engine.DiskCacheStrategy.NONE)
                                        .into(imgResult);
                                if (txtStatus != null) txtStatus.setText("✅ 修正完了！");
                            } catch (Exception e) {
                                if (txtStatus != null) txtStatus.setText("❌ 保存エラー: " + e.getMessage());
                            }
                        } else {
                            if (txtStatus != null) txtStatus.setText("❌ 画像を生成できませんでした。再度お試しください。");
                        }
                    });
                } catch (Exception e) {
                    runOnUiThread(() -> {
                        btnRefine.setEnabled(true);
                        etRefine.setEnabled(true);
                        if (txtStatus != null) txtStatus.setText("❌ エラー: " + e.getMessage());
                    });
                }
            });
        });
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        chatExecutor.shutdownNow();
    }
}
